mapper.select:

SELECT 
	ID,
	CONTENT,
	VALID,
	LAST_UPDATE_DATE,
	LAST_UPDATED_BY,
	CREATION_DATE,
	CREATED_BY,
	ENABLED_FLAG,
	ANSWER_IDX,
	QUESTION_ID
FROM 
	EXAM_ANSWER
WHERE
	ENABLED_FLAG=1


AND ID=#{id}


AND CONTENT=#{content}


AND upper(VALID) like upper('%${valid}%')


AND LAST_UPDATE_DATE=#{lastUpdateDate}


AND LAST_UPDATED_BY=#{lastUpdatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}


AND ENABLED_FLAG=#{enabledFlag}


AND upper(ANSWER_IDX) like upper('%${answerIdx}%')


AND QUESTION_ID=#{questionId}

ORDER BY ID


SELECT 
	*
FROM 
	EXAM_ANSWER
WHERE
	ENABLED_FLAG=1


AND ID=#{bo.id}


AND CONTENT=#{bo.content}


AND upper(VALID) like upper('%${bo.valid}%')


AND LAST_UPDATE_DATE=#{bo.lastUpdateDate}


AND LAST_UPDATED_BY=#{bo.lastUpdatedBy}


AND CREATION_DATE=#{bo.creationDate}


AND CREATED_BY=#{bo.createdBy}


AND ENABLED_FLAG=#{bo.enabledFlag}


AND upper(ANSWER_IDX) like upper('%${bo.answerIdx}%')


AND QUESTION_ID=#{bo.questionId}

ORDER BY ${page.sortFieldName} DESC
